#[allow(clippy::missing_errors_doc)]
#[extendr]
pub fn convert(html: String, options: Option<ConversionOptions>, visitor: Option<extendr_api::Robj>) -> Result<ConversionResult> {
    let visitor: Option<html_to_markdown_rs::visitor::VisitorHandle> = match visitor {
        Some(v) if !v.is_null() => {
            let bridge = RHtmlVisitorBridge::new(v);
            Some(std::rc::Rc::new(std::cell::RefCell::new(bridge)) as html_to_markdown_rs::visitor::VisitorHandle)
        },
        _ => None,
    };
    let options_core: Option<html_to_markdown_rs::ConversionOptions> = options.as_deref().filter(|s| *s != "NULL").map(|s| serde_json::from_str(s).map_err(|e| extendr_api::Error::Other(e.to_string()))).transpose()?;
    html_to_markdown_rs::convert(&html, options_core, visitor).map(|val| val.into()).map_err(|e| extendr_api::Error::Other(e.to_string()))
}


fn nodecontext_to_robj(
    ctx: &html_to_markdown_rs::visitor::NodeContext,
) -> extendr_api::Robj {
    use extendr_api::prelude::*;
    let attrs: extendr_api::Robj = ctx.attributes.iter()
        .map(|(k, v)| (k.as_str(), extendr_api::Robj::from(v.as_str())))
        .collect::<List>().into();
    list!(
        node_type = format!("{:?}", ctx.node_type),
        tag_name = ctx.tag_name.as_str(),
        depth = ctx.depth as i32,
        index_in_parent = ctx.index_in_parent as i32,
        is_inline = ctx.is_inline,
        parent_tag = ctx.parent_tag.as_deref().unwrap_or(""),
        attributes = attrs,
    ).into()
}

